# 기존 JSON 불러오기
with open("app/lib/saju/solarTermsKASI.json", "r", encoding="utf-8") as f:
    existing = json.load(f)

# 형식 변환 후 병합
for year, terms in data_1926_1959.items():
    existing[year] = {}
    for name, arr in terms.items():
        existing[year][name] = {
            "month": arr[0], "day": arr[1],
            "hour": arr[2], "minute": arr[3],
        }

# 저장
with open("app/lib/saju/solarTermsKASI.json", "w", encoding="utf-8") as f:
    json.dump(existing, f, ensure_ascii=False, indent=2)

print(f"완료! 총 {len(existing)}년치")
print(f"범위: {min(existing.keys())} ~ {max(existing.keys())}")